VALUES
  ('social-worker-moex-07400', 'social-worker', 'social-worker-moex-101-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於西方社會福利的發展，下列敘述何者正確？', '["最早的社會福利立法出現於1501年英國的濟貧法", "美國總統柯林頓提出福利新保守主義", "1883年著名的貝佛理奇報告書是為了對抗五害而提出福利國家的藍圖", "英國工黨於1997年執政後，逐步採取從福利到工作（welfare to work）的政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d90f7a035be7", "answer_pdf_sha1": "0daae4475aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07401', 'social-worker', 'social-worker-moex-101-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '老人福利法第19條規定為滿足居住機構老人多元需求，主管機關應輔導老人福利機構依老人需求提供各 項機構式服務，而且該機構式服務應以什麼為原則，下列何者正確？', '["結合家庭及社區生活", "強調在地老化", "善用社會資源", "發揮老人友善關懷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d90f7a035be7", "answer_pdf_sha1": "0daae4475aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07402', 'social-worker', 'social-worker-moex-101-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於普及性（universal）福利與選擇性（selective）福利的描述，下列何者正確？', '["目前國內實施的敬老年金是一項普及性福利", "普及性福利的行政成本較高", "普及性福利強調公民權利及平等主義", "選擇性福利可以預防社會問題的出現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d90f7a035be7", "answer_pdf_sha1": "0daae4475aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07403', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '陳子昂作〈登幽州臺歌〉：「前不見古人，後不見來者。念天地之悠悠，獨愴然而涕下。」以抒發其面 對時間的恆長，而意識到人生命短暫孤寂的悲嘆感情。下列詩文所流露的情感與此最相近的是：', '["知天之長，而吾所歷者短，則遇憂患橫逆之來，當少忍以待其定（曾國藩《曾國藩日記》）", "人生只似風前絮，歡也零星，悲也零星，都作連江點點萍（王國維〈採桑子〉）", "死生，命也，其有夜旦之常，天也。人之有所不得與，皆物之情也（《莊子．大宗師》）", "老驥伏櫪，志在千里。烈士暮年，壯心不已（曹操〈步出夏門行．龜雖壽〉）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07404', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩歌，流露出批判戰爭的選項是：', '["漢家旌旗滿陰山，不遣胡兒馬匹還。願得此身長報國，何須生入玉門關（戴叔倫〈塞上曲〉）", "弓背霞明劍照霜，秋風走馬出咸陽。未收天子河 湟地，不擬回頭望故鄉（令狐楚〈少年行〉）", "何代何王不戰爭？盡從離亂見清平。如今暴骨多於土，猶點鄉兵作戍兵（韋莊〈憫耕者〉）", "金帶連環束戰袍，馬頭衝雪度臨洮。捲旗夜劫單于帳，亂斫胡兒缺寶刀（馬戴〈出塞詞〉）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07405', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①萬木凍欲折，孤根暖獨回。前村深雪裡，昨夜一枝開', '["一樹春風千萬枝，嫩于金色軟于絲。永豐西角荒園裡，盡日無人屬阿誰", "自讀西湖處士詩，年年臨水看幽姿。晴窗畫出橫斜影，絕勝前村夜雪時", "嫋嫋古堤邊，青青一數煙。若為絲不斷，留取繫郎船 ⑤含煙惹霧每依依，萬緒千條拂落暉。為報行人休盡折，半留相送半迎歸 ⑥愁鎖巴雲往事空，只將遺恨寄芳叢。歸心千古終難白，啼血萬山都是紅 上列詩句，描摹柳樹的是：", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07406', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①以五十步笑百步，則何如？曰：不可，「直」不百步耳，是亦走也（《孟子．梁惠王》）／寡人非能 好先王樂也，「直」好世俗之樂耳（《孟子．梁惠王》）', '["「歸」於汪，汪故貧，先君子以為贅婿（汪中〈先母鄒孺人靈表〉）／句踐之困於會稽，而「歸」臣 妾於吳（《史記．越王句踐世家》）", "燕趙處秦革滅「殆」盡之際，可謂智力孤危（蘇洵〈六國論〉）／學而不思則罔，思而不學則「殆」 （《論語．為政》）", "當二公之初守也，寧能知人之卒不救，棄城而「逆」遁（韓愈〈張中丞傳後敘〉）／眾人所趨，勢之 所歸，雖有大力莫之敢「逆」（曾國藩〈原才〉） ⑤小學而大「遺」，吾未見其明也（韓愈〈師說〉）／君子篤於親，則民興於仁；故舊不「遺」，則民 不偷。（《論語．泰伯》） ⑥匣而埋諸土，年出之，抱以「適」市（劉基《郁離子》）／使其中坦然，不以物傷性，將何「適」而 非快（蘇轍〈黃州快哉亭記〉） 以上各組文句「」內字義相同的選項是：", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07407', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '辛棄疾〈鷓鴣天〉：「壯歲旌旗擁萬夫，錦襜突騎渡江初。燕兵夜娖銀胡籙，漢箭朝飛金僕姑。追往事， 嘆今吾，春風不染白髭鬚。卻將萬字平戎策，換得東家種樹書」，此闋詞所傳達的情境，下列何者最為 妥適？', '["曉戰隨金鼓，宵眠抱玉鞍。願將腰下劍，直為斬樓蘭", "昔時飛箭無全目，今日垂楊生左肘。路旁時賣故侯瓜，門前學種先生柳", "大漠孤煙直，長河落日圓。蕭關逢候騎，都護在燕然", "青海長雲暗雪山，孤城遙望玉門關。黃沙百戰穿金甲，不破樓蘭終不還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07408', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《荀子．解蔽》：「夏首之南有人焉，曰涓蜀梁。其為人也，愚而善畏。明月而宵行，俯見其影，以為 伏鬼也。卬視其髮，以為立魅也。背而走，比至其家，失氣而死」，如果用成語來描寫本寓言所形容的 心理狀態，下列選項那一個最不合適？', '["杯弓蛇影", "風聲鶴唳", "疑心暗鬼", "燭影斧聲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07409', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '請仔細閱讀、品賞文氣與思理後，將下列各段文句重組，排成一個合理而流暢的長句：①今學者曠廢隳', '["雖百工技藝，未有不本於志者", "志不立，天下無可成之事", "而百無所成，皆由於 志之未立耳", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
